class Solution:
    def consecutiveSetBits(self, n: int) -> bool:
        bits = bin(n)[2:]
        pairs = 0
        for i in range(len(bits) - 1):
            if bits[i] == '1' and bits[i+1] == '1':
                pairs += 1
        return pairs == 1

solutions.javascript:
var consecutiveSetBits = function(n) {
    let pairs = 0;
    let prev = 0;
    let x = n;
    let first = true;
    while (x > 0) {
        const bit = x & 1;
        if (!first && bit === 1 && prev === 1) pairs++;
        prev = bit;
        first = false;
        x = x >>> 1;
    }
    return pairs === 1;
};
